-- Migration 0019: Auth identity rewiring
-- Replace person_id with identity_id on session, account tables.
-- Update OAuth tables userId from record<person> to record<identity>.
-- better-auth user model now maps to identity table instead of person.
-- Add better-auth user fields to identity table (contact_email, email_verified, image, updated_at).

BEGIN TRANSACTION;

-- Identity table: add fields required by better-auth user model
DEFINE FIELD OVERWRITE contact_email ON identity TYPE option<string>;
DEFINE FIELD OVERWRITE email_verified ON identity TYPE option<bool>;
DEFINE FIELD OVERWRITE image ON identity TYPE option<string>;
DEFINE FIELD OVERWRITE updated_at ON identity TYPE option<datetime>;

-- Identity table: make workspace optional (identity created at sign-up before workspace exists)
DEFINE FIELD OVERWRITE workspace ON identity TYPE option<record<workspace>>;

-- Identity table: add default for type so better-auth can create identity records
DEFINE FIELD OVERWRITE type ON identity TYPE string DEFAULT 'human' ASSERT $value IN ['human', 'agent', 'system'];

-- Session: replace person_id with identity_id
REMOVE FIELD person_id ON session;
DEFINE FIELD OVERWRITE identity_id ON session TYPE record<identity>;

-- Account: replace person_id with identity_id
REMOVE FIELD person_id ON account;
DEFINE FIELD OVERWRITE identity_id ON account TYPE record<identity>;

-- OAuth tables: userId from record<person> to record<identity>
DEFINE FIELD OVERWRITE userId ON oauthClient TYPE option<record<identity>>;
DEFINE FIELD OVERWRITE userId ON oauthAccessToken TYPE option<record<identity>>;
DEFINE FIELD OVERWRITE userId ON oauthRefreshToken TYPE option<record<identity>>;
DEFINE FIELD OVERWRITE userId ON oauthConsent TYPE option<record<identity>>;

COMMIT TRANSACTION;

